server.registerTool(
  "get-sync-status",
  {
    description: "Use when: checking whether iCloud sync is in progress before trusting read results.\nReturns: sync active/idle, pending upload count, and seconds since last change.\nDo not use when: you need note data \u2014 this is a read-only diagnostics tool.",
    inputSchema: {},
    outputSchema: {
      syncDetected: external_exports.boolean().optional(),
      pendingUpload: external_exports.number().optional(),
      secondsSinceLastChange: external_exports.number().optional(),
      recentActivity: external_exports.boolean().optional(),
      warning: external_exports.string().optional(),
      error: external_exports.string().optional()
    }
  },
  withErrorHandling(() => {
    const status = getSyncStatus();
    if (status.error) {
      return successResponse(`\u26A0\uFE0F Sync status unknown: ${status.error}`, { ...status });
    }
    const lines = [];
    if (status.syncDetected) {
      lines.push("\u{1F504} iCloud Sync: ACTIVE");
      lines.push("");
      if (status.pendingUpload > 0) {
        lines.push(`  \u2022 ${status.pendingUpload} item(s) pending upload`);
      }
      if (status.recentActivity) {
        lines.push(`  \u2022 Database modified ${status.secondsSinceLastChange}s ago`);
      }
      lines.push("");
      lines.push("\u26A0\uFE0F Note: Operations may return incomplete results during sync.");
    } else {
      lines.push("\u2713 iCloud Sync: Idle");
      lines.push("");
      lines.push(`  Last activity: ${status.secondsSinceLastChange}s ago`);
    }
    return successResponse(lines.join("\n"), { ...status });
  }, "Error checking sync status")
);
