server.registerTool(
  "get-note-markdown",
  {
    description: "Use when: reading a note as Markdown, with checklist items annotated [x]/[ ] when Full Disk Access is granted.\nReturns: the note's Markdown.\nDo not use when: you need the raw HTML/plaintext body (get-note-content) or only metadata (get-note-details).\nNote: falls back to plain lists (no checkmarks) without Full Disk Access.",
    inputSchema: {
      id: external_exports.string().max(MAX.ID).optional().describe("Note ID (preferred - more reliable than title)"),
      title: external_exports.string().max(MAX.TITLE).optional().describe("Note title (use id instead when available)"),
      account: external_exports.string().max(MAX.ACCOUNT).optional().describe("Account containing the note (ignored if id is provided)")
    },
    outputSchema: {
      markdown: external_exports.string().optional()
    }
  },
  withErrorHandling(({ id, title, account }) => {
    if (id) {
      const markdown2 = notesManager.getNoteMarkdownById(id);
      if (!markdown2) {
        return errorResponse(`Note with ID "${id}" not found or has no content`);
      }
      return successResponse(markdown2, { markdown: markdown2 });
    }
    if (!title) {
      return errorResponse("Either 'id' or 'title' is required");
    }
    const markdown = notesManager.getNoteMarkdown(title, account);
    if (!markdown) {
      return errorResponse(
        `Note "${title}" not found or has no content. Use search-notes to find notes, then use the note's ID for reliable operations.`
      );
    }
    return successResponse(markdown, { markdown });
  }, "Error getting note as markdown")
);
server.registerTool(
  "get-checklist-state",
  {
    description: "Use when: reading the checked/unchecked state of a note's checklist items, by id.\nReturns: each item's text and done state plus checked/total counts.\nDo not use when: you only have a title (get the id via search-notes first) or want the full body text (get-note-content).\nNote: requires Full Disk Access; reads the NoteStore database directly.",
    inputSchema: {
      id: external_exports.string().min(1, "Note ID is required. Use search-notes to find the note ID first.").max(MAX.ID)
    },
    outputSchema: {
      items: external_exports.array(external_exports.object({}).passthrough()).optional(),
      checked: external_exports.number().optional(),
      total: external_exports.number().optional()
    }
  },
  withErrorHandling(({ id }) => {
    const note = notesManager.getNoteById(id);
    if (!note) {
      return errorResponse(`Note with ID "${id}" not found`);
    }
    if (note.passwordProtected) {
      return errorResponse(
        `Note "${note.title}" is password-protected and cannot be read. Unlock it in Notes.app first.`
      );
    }
    const result = getChecklistItems(id);
    if (!result.items) {
      return errorResponse(result.message || "Failed to read checklist state.");
    }
    const summary = result.items.map((item) => `${item.done ? "[x]" : "[ ]"} ${item.text}`).join("\n");
    const checked = result.items.filter((i) => i.done).length;
    return successResponse(
      `Checklist for "${note.title}" (${checked}/${result.items.length} done):
${summary}`,
      { items: result.items, checked, total: result.items.length }
    );
  }, "Error reading checklist state")
);
server.registerTool(
  "get-note-metadata",
  {
    description: "[BETA] Use when: reading note metadata AppleScript cannot expose \u2014 pinned state, checklist flags, trash/recovery state, preview snippet, password hint \u2014 by id.\nReturns: a metadata object; fields vary by macOS version and are omitted when unavailable.\nDo not use when: you need the body (get-note-content) or per-item checklist state (get-checklist-state).\nNote: reads the NoteStore SQLite database read-only and requires Full Disk Access. BETA \u2014 the database schema changes between macOS releases, so some fields may be absent. Works on trashed notes that AppleScript can no longer resolve.",
    inputSchema: {
      id: external_exports.string().min(1, "Note ID is required. Use search-notes to find the note ID first.").max(MAX.ID)
    },
    outputSchema: {
      pinned: external_exports.boolean().optional(),
      hasChecklist: external_exports.boolean().optional(),
      hasChecklistInProgress: external_exports.boolean().optional(),
      recoveringFromTrash: external_exports.boolean().optional(),
      passwordProtected: external_exports.boolean().optional(),
      passwordHint: external_exports.string().optional(),
      snippet: external_exports.string().optional(),
      widgetSnippet: external_exports.string().optional(),
      smartFolderQuery: external_exports.string().optional()
    }
  },
  withErrorHandling(({ id }) => {
    const { metadata, message } = getNoteMetadata(id);
    if (!metadata) {
      return errorResponse(message || `Failed to read metadata for note "${id}"`);
    }
    const keys = Object.keys(metadata);
    const summary = keys.length === 0 ? `No additional metadata is available for note "${id}" on this macOS version.` : keys.map((k) => `${k}: ${String(metadata[k])}`).join("\n");
    return successResponse(summary, metadata);
  }, "Error reading note metadata")
);
